 1	import * as React from 'react';
 2	import { Button, Popover } from '@patternfly/react-core';
 3	import { QuestionCircleIcon } from '@patternfly/react-icons';
 4	import { useTranslation } from 'react-i18next';
 5	import { Shortcut, ShortcutTable } from '../../shortcuts';
 6	
 7	const TaskSidebarShortcuts: React.FC = () => {
 8	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 9	
10	  return (
11	    <Popover
12	      aria-label={t('View shortcuts')}
13	      bodyContent={
14	        <ShortcutTable>
15	          <Shortcut ctrl keyName="space">
16	            {t('Activate auto complete')}
17	          </Shortcut>
18	        </ShortcutTable>
19	      }
20	      maxWidth="25rem"
21	      distance={18}
22	    >
23	      <Button type="button" variant="link" isInline>
24	        <QuestionCircleIcon className="co-icon-space-r co-p-has-sidebar__sidebar-link-icon" />
25	        {t('View shortcuts')}
26	      </Button>
27	    </Popover>
28	  );
29	};
30	
31	export default TaskSidebarShortcuts;

